class Counter {
    private int count = 0;

    // synchronizedメソッド（thisでロック）
    public synchronized void increment() {
        count++;
    }

    // synchronizedブロック
    public void decrement() {
        synchronized (this) {
            count--;
        }
    }

    // staticメソッドのsynchronized（Classオブジェクトでロック）
    private static int total = 0;
    public static synchronized void addTotal(int n) {
        total += n;
    }

    // 任意のオブジェクトでロック
    private final Object lock = new Object();
    public void safeOp() {
        synchronized (lock) {
            // lockオブジェクトでロック
            count++;
        }
    }
}

// UnsafeCounterクラスの定義
class UnsafeCounter {
    private int count = 0;
    // incrementメソッドの定義
    public void increment() { count++; } // 同期化なし！
    // getCountメソッドの定義
    public int getCount() { return count; }
}

// SafeCounterクラスの定義
class SafeCounter {
    private int count = 0;
    public synchronized void increment() { count++; } // 同期化あり
    public synchronized int getCount() { return count; }
}

// テスト
UnsafeCounter unsafe = new UnsafeCounter();
// 繰り返し処理（for文）
for (int i = 0; i < 1000; i++) {
    new Thread(() -> unsafe.increment()).start();
}
Thread.sleep(2000);
System.out.println(unsafe.getCount()); // 1000未満の可能性あり

SafeCounter safe = new SafeCounter();
// 繰り返し処理（for文）
for (int i = 0; i < 1000; i++) {
    new Thread(() -> safe.increment()).start();
}
Thread.sleep(2000);
System.out.println(safe.getCount()); // 常に1000

class Reentrant {
    public synchronized void methodA() {
        System.out.println("A");
        methodB(); // 同じオブジェクトのsynchronizedメソッドを呼べる
    }

    public synchronized void methodB() {
        System.out.println("B");
    }
}

// methodA()を呼ぶと、thisのロックを取得
// methodA()内でmethodB()を呼ぶ際、既にロックを保持しているので再取得可能
Reentrant r = new Reentrant();
new Thread(() -> r.methodA()).start();
// 出力: A B

