import java.util.concurrent.ConcurrentHashMap;

ConcurrentHashMap<String, Integer> map = new ConcurrentHashMap<>();
map.put("A", 1);
map.put("B", 2);

// アトミック操作
map.putIfAbsent("C", 3);  // キーCが存在しない場合のみ追加
map.replace("A", 1, 10);  // 値が1の場合のみ10に置き換え
map.compute("B", (k, v) -> v + 100); // アトミックに計算して更新

System.out.println(map); // {A=10, B=102, C=3}

// nullは許可されない
try {
    map.put("D", null); // NullPointerException
} catch (NullPointerException e) {
    System.out.println("null not allowed");
}

// イテレーション中の変更も安全
map.forEach((k, v) -> {
    if (v > 50) map.remove(k); // ConcurrentModificationExceptionは発生しない
});

