import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

// AtomicInteger
AtomicInteger counter = new AtomicInteger(0);
counter.incrementAndGet(); // 1（++counterに相当）
counter.getAndIncrement(); // 1を返し、値は2に（counter++に相当）
counter.addAndGet(10);     // 12
counter.compareAndSet(12, 20); // true（12→20に更新）
System.out.println(counter.get()); // 20

// AtomicReference
AtomicReference<String> ref = new AtomicReference<>("Hello");
ref.set("World");
System.out.println(ref.get()); // World
ref.compareAndSet("World", "Java"); // true
System.out.println(ref.get()); // Java

// スレッドセーフなカウンター（synchronizedなし）
AtomicInteger safeCount = new AtomicInteger(0);
for (int i = 0; i < 1000; i++) {
    new Thread(() -> safeCount.incrementAndGet()).start();
}

// デッドロックの例
Object lockA = new Object();
Object lockB = new Object();

Thread t1 = new Thread(() -> {
    synchronized (lockA) {
        System.out.println("T1: lockA acquired");
        // 例外が発生する可能性がある処理
        try { Thread.sleep(100); } catch (InterruptedException e) {}
        synchronized (lockB) { // lockBを待つ
            System.out.println("T1: lockB acquired");
        }
    }
});

Thread t2 = new Thread(() -> {
    synchronized (lockB) {
        System.out.println("T2: lockB acquired");
        // 例外が発生する可能性がある処理
        try { Thread.sleep(100); } catch (InterruptedException e) {}
        synchronized (lockA) { // lockAを待つ
            System.out.println("T2: lockA acquired");
        }
    }
});

t1.start();
t2.start();
// T1はlockB待ち、T2はlockA待ち → デッドロック！

// 防止策：ロック順序を統一する
// 両方のスレッドで lockA → lockB の順に取得する

class SharedData {
    private boolean ready = false;

    public synchronized void waitForReady() throws InterruptedException {
        while (!ready) {  // whileループでの条件チェックが重要
            wait();  // readyになるまで待機
        }
        System.out.println("Data is ready!");
    }

    public synchronized void setReady() {
        ready = true;
        notifyAll();  // 待機中のスレッドをすべて起こす
    }
}

SharedData data = new SharedData();

Thread waiter = new Thread(() -> {
    try { data.waitForReady(); }
    catch (InterruptedException e) {}
});

Thread setter = new Thread(() -> {
    try { Thread.sleep(1000); } catch (InterruptedException e) {}
    data.setReady();
});

waiter.start();
setter.start();

